import re
KNOWN_FACTS={'Nigeria capital':'Abuja','Python creator':'Guido van Rossum','FastAPI creator':'Sebastián Ramírez'}
BIAS_WORDS=['always','never','all','none','every','typical','normal for']
def check_hallucination(response,facts=KNOWN_FACTS):
    issues=[]
    for fact_key,fact_val in facts.items():
        if fact_key.lower() in response.lower():
            if fact_val.lower() not in response.lower():
                issues.append(f'Possible error about:{fact_key}')
    return issues
def check_bias(response):
    return[w for w in BIAS_WORDS if w in response.lower()]
def filter_pii(text):
    text=re.sub(r'[\w.-]+@[\w.-]+\.\w+','[EMAIL]',text)
    text=re.sub(r'(\+234|0)[0-9]{10}','[PHONE]',text)
    text=re.sub(r'\b[0-9]{11}\b','[NIN]',text)
    return text
def safety_wrap(prompt,response):
    report={'prompt':prompt,'original':response}
    report['hallucination_flags']=check_hallucination(response)
    report['bias_flags']=check_bias(response)
    report['filtered_response']=filter_pii(response)
    report['safe']=not report['hallucination_flags'] and not report['bias_flags']
    return report
test_cases=[('What is the capital?','The capital of Nigeria is Lagos.'),('Tell me about students.','All Nigerian students always struggle with programming.'),('Contact info?','Email ada@example.com or call +2348012345678')]
for prompt,response in test_cases:
    result=safety_wrap(prompt,response)
    print(f'Q:{prompt}')
    print(f'Safe:{result["safe"]} Flags:{result["hallucination_flags"]+result["bias_flags"]}')
    print(f'Filtered:{result["filtered_response"]}')
    print()
